            // Check if current path can form a palindrome
            let oddCount = 0;
            let total = 0;
            for (const count of charCount.values()) {
                if (count % 2 === 1) {
                    oddCount++;
                }
                total += count;
            }
            if (oddCount <= 1 && total > maxLength) {
                maxLength = total;
